		// 校验验证码
		String captcha = jsonObject.getString("captcha");
		// 代码逻辑说明: VUEN-2245 【漏洞】发现新漏洞待处理20220906
		String redisKey = CommonConstant.PHONE_REDIS_KEY_PRE+phone;
